{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "umberhold/schemas/time/world-clock-state.schema.json",
  "title": "Umberhold World Clock State",
  "type": "object",
  "additionalProperties": false,
  "required": ["absolute_step"],
  "properties": {
    "absolute_step": {
      "type": "integer",
      "minimum": 0,
      "description": "Total elapsed 6-second steps since the campaign epoch."
    },
    "cached_day_number": {
      "type": "integer",
      "minimum": 1,
      "description": "Optional derived cache."
    },
    "cached_step_of_day": {
      "type": "integer",
      "minimum": 0,
      "maximum": 14399,
      "description": "Optional derived cache."
    },
    "cached_phase_id": {
      "$ref": "./time-types.schema.json#/$defs/dayPhaseId"
    }
  }
}

