{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "umberhold/schemas/quests/quest-journal.schema.json",
  "title": "Umberhold Quest Journal State",
  "type": "object",
  "additionalProperties": false,
  "required": ["journal_ui", "entries"],
  "properties": {
    "journal_ui": {
      "$ref": "#/$defs/journalUi"
    },
    "entries": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/journalEntry"
      }
    }
  },
  "$defs": {
    "status": {
      "type": "string",
      "enum": ["incomplete", "complete"]
    },
    "objective": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "text", "status"],
      "properties": {
        "id": {
          "type": "string"
        },
        "text": {
          "type": "string"
        },
        "status": {
          "$ref": "#/$defs/status"
        }
      }
    },
    "journalUi": {
      "type": "object",
      "additionalProperties": false,
      "required": ["icon", "available_in", "blocked_in_combat"],
      "properties": {
        "icon": {
          "type": "string",
          "const": "book"
        },
        "available_in": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "string",
            "enum": ["village", "exploration", "combat"]
          },
          "description": "Player-facing contexts where the Journal button is visible."
        },
        "blocked_in_combat": {
          "type": "boolean"
        },
        "notes": {
          "type": "string"
        }
      }
    },
    "journalEntry": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "quest_id",
        "title",
        "status",
        "source",
        "source_summary",
        "quest_summary",
        "objectives"
      ],
      "properties": {
        "quest_id": {
          "type": "string"
        },
        "title": {
          "type": "string"
        },
        "status": {
          "$ref": "#/$defs/status"
        },
        "source": {
          "type": "string",
          "description": "NPC or interaction that created the entry."
        },
        "source_summary": {
          "type": "string",
          "description": "Player-facing summary of what the source NPC or interaction communicated."
        },
        "quest_summary": {
          "type": "string",
          "description": "Current narrative state of the quest."
        },
        "objectives": {
          "type": "array",
          "minItems": 1,
          "items": {
            "$ref": "#/$defs/objective"
          }
        },
        "completion_note": {
          "type": "string"
        },
        "started_by_flags": {
          "type": "array",
          "items": {
            "type": "string"
          }
        },
        "completed_by_flags": {
          "type": "array",
          "items": {
            "type": "string"
          }
        },
        "last_updated_step": {
          "type": "integer",
          "minimum": 0
        }
      }
    }
  }
}

