  "$id": "umberhold/schemas/locations/umberhold-village.schema.json",
  "title": "Umberhold Village Content Definition",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "id",
    "name",
    "overview",
    "design_intent",
    "journal_ui",
    "locations",
    "npcs",
    "quests",
    "progression"
  ],
  "properties": {
    "id": {
      "type": "string",
      "const": "umberhold"
    },
    "name": {
      "type": "string",
      "const": "Umberhold"
    },
    "overview": {
      "type": "string"
    },
    "design_intent": {
      "$ref": "#/$defs/designIntent"
    },
    "journal_ui": {
      "$ref": "#/$defs/journalUi"
    },
    "locations": {
      "type": "array",
      "minItems": 1,
      "items": {
        "$ref": "#/$defs/location"
      }
    },
    "npcs": {
      "type": "array",
      "minItems": 1,
      "items": {
        "$ref": "#/$defs/npc"
      }
    },
    "quests": {
      "type": "array",
      "minItems": 1,
      "items": {
