{"path":"umberhold/examples/locations/umberhold-village.example.json","content":"{
  "$schema": "../../schemas/locations/umberhold-village.schema.json",
  "id": "umberhold",
  "name": "Umberhold",
  "overview": "A muddy, decaying village that serves as the opening hub. Gravenhold Manor looms to the northwest, the graveyard stirs to the east, and the village well has become a deadly immediate threat.",
  "design_intent": {
    "structure": "sandbox_hub",
    "intended_first_path": "gravenhold_manor",
    "soft_gating": true,
    "failure_expected": true,
    "difficulty_signposting": [
      {
        "content_id": "gravenhold_manor",
        "message": "Dangerous, but the clearest first move."
      },
      {
        "content_id": "east_graveyard",
        "message": "Available early, but deadlier than it first appears."
      },
      {
        "content_id": "village_well",
        "message": "Immediate combat set piece; very dangerous if attempted too early."
      }
    ]
  },
  "journal_ui": {
    "icon": "book",
    "available_in": ["village", "exploration"],
    "blocked_in_combat": true
  },
  "locations": [
    {
      "id": "umberhold_inn",
      "name": "Umberhold Inn",
      "location_type": "service_hub",
      "summary": "The party's safest base in the village and the only reliable save point.",
      "npc_ids": ["bartholomew"],
      "services": [
        {
          "id": "rest",
          "label": "Rest",
          "effect": "long_rest",
          "cost_gp": 25,
          "notes": "Free if a Troubadour is in the party."
        },
        {
          "id": "rest_until_dawn",
          "label": "Rest Until Dawn",
          "effect": "pass_time"
        },
        {
          "id": "save_game",
          "label": "Save Game",
          "effect": "open_save_ui"
        },
        {
          "id": "load_game",
          "label": "Load Game",
          "effect": "open_load_ui"
        }
      ]
    },
    {
      "id": "iron_shovel_and_scutage",
      "name": "Iron Shovel & Scutage",
      "location_type": "service_hub",
      "summary": "General gear shop and item identification service.",
      "npc_ids": ["oswaldine"],
      "services": [
        {
          "id": "buy",
          "label": "Buy",
          "effect": "open_shop_buy"
        },
        {
          "id": "sell",
          "label": "Sell",
          "effect": "open_shop_sell",
          "notes": "Pays 50% value."
        },
        {
          "id": "identify",
          "label": "Identify",
          "effect": "identify_item",
          "cost_gp": 125
        }
      ]
    },
    {
      "id": "solcine_chantry",
      "name": "Solcine Chantry",
      "location_type": "service_hub",
      "summary": "Healing, holy goods, and resurrection services.",
      "npc_ids": ["gidney"],
      "services": [
        {
          "id": "cure_poison",
          "label": "Cure Poison",
          "effect": "remove_poison",
          "cost_gp": 100
        },
        {
          "id": "cure_disease",
          "label": "Cure Disease",
          "effect": "remove_disease",
          "cost_gp": 100
        },
        {
          "id": "remove_curse",
          "label": "Remove Curse",
          "effect": "remove_curse",
          "cost_gp": 100
        }
      ]
    },
    {
      "id": "alchemists_mortar",
      "name": "Alchemist's Mortar",
      "location_type": "quest_site",
      "summary": "Locked at game start. Inspecting it begins the missing alchemist thread.",
      "npc_ids": ["etheldreda"],
      "interaction_rules": [
        "Inspecting the note starts The Missing Alchemist.",
        "The shop remains closed until Etheldreda is rescued.",
        "After rescue, potion services unlock."
      ],
      "journal_trigger": "the_missing_alchemist"
    },
    {
      "id": "bailiffs_desk",
      "name": "The Bailiff's Desk",
      "location_type": "service_hub",
      "summary": "Primary quest dispatch point for village troubles.",
      "npc_ids": ["wymarc"]
    },
    {
      "id": "village_well",
      "name": "Village Well",
      "location_type": "set_piece_combat",
      "summary": "A rope-and-bucket descent directly into a troll encounter below the well.",
      "interaction_rules": [
        "The party may descend using the rope and bucket rig.",
        "Descending hands off directly to combat.",
        "There is no well dungeon to explore.",
        "After victory, the party climbs back up."
      ],
      "encounter_transition": "direct_to_combat_grid",
      "journal_trigger": "troll_trouble"
    },
    {
      "id": "east_graveyard",
      "name": "East Graveyard",
      "location_type": "single_level_dungeon_entrance",
      "summary": "A disturbed graveyard whose rear mausoleum stair leads to a single-level 26x26 dungeon below.",
      "interaction_rules": [
        "The rear mausoleum contains the descent stair.",
        "The dungeon below is one level only.",
        "The graveyard content is intended to be deadlier than the manor route."
      ],
      "encounter_transition": "enter_single_level_dungeon",
      "journal_trigger": "the_restless_dead"
    },
    {
      "id": "south_gates",
      "name": "South Gates",
      "location_type": "progression_lock",
      "summary": "The village exit remains shut until the manor threat is broken below ground.",
      "npc_ids": ["halvric"],
      "unlock_flag": "south_gate_unlocked"
    }
  ],
  "npcs": [
    {
      "id": "bartholomew",
      "name": "Bartholomew",
      "role": "innkeeper",
      "summary": "A weary innkeeper with kind eyes and a cautious voice.",
      "dialogue": {
        "default": [
          "Keep your voice low… walls carry sound these days.",
          "Used to be folk laughed here. Now they listen. Always listening."
        ],
        "after_missing_alchemist": [
          "Word travels fast. Etheldreda’s back, and that’s more good news than we’ve had in months."
        ],
        "after_restless_dead": [
          "Heard bells at the graveyard this morning. Proper mourning bells."
        ],
        "after_troll_trouble": [
          "Water’s flowing and the buckets are filling. Strange how hopeful that sounds."
        ],
        "after_all_three": [
          "Still wouldn’t call this place safe. But I’d call it living."
        ]
      }
    },
    {
      "id": "oswaldine",
      "name": "Oswaldine",
      "role": "merchant",
      "summary": "A hard-faced trader with a sharp tongue and sharper instincts.",
      "dialogue": {
        "default": [
          "Gold talks. If you’ve got it, I’ve got something worth your trouble.",
          "If you’re going down that shaft, buy oil. And if you’re clever, fire."
        ],
        "after_missing_alchemist": [
          "Good. The alchemist’s alive. Means I can stop getting asked for brews I don’t stock."
        ],
        "after_restless_dead": [
          "East side’s calmed down some. Grim trade is still trade, but panic’s worse."
        ],
        "after_troll_trouble": [
          "Water trade’s back. Turns out civilization matters."
        ],
        "after_all_three": [
          "Village still limps. But it’s limping forward now."
        ]
      }
    },
    {
      "id": "gidney",
      "name": "Acolyte Gidney",
      "role": "acolyte",
      "summary": "Soft-spoken but resolute. One of the few calm presences in Umberhold.",
      "dialogue": {
        "default": [
          "Solace watches, even here… though her light feels distant.",
          "The earth there is troubled. The dead are not at rest."
        ],
        "after_missing_alchemist": [
          "One life returned is no small mercy."
        ],
        "after_restless_dead": [
          "The graveyard is quieter now. Not silent—but no longer pleading."
        ],
        "after_troll_trouble": [
          "Clean water is a blessing most only notice when it is threatened."
        ],
        "after_all_three": [
          "The darkness has thinned, but it has not withdrawn."
        ]
      }
    },
    {
      "id": "wymarc",
      "name": "Wymarc",
      "role": "bailiff",
      "summary": "A stout, restless man buried in parchment and worry.",
      "suspicious_detail": "He becomes tense and avoids eye contact when Etheldreda is mentioned.",
      "dialogue": {
        "default": [
          "Ah—new faces. Good. Means you’ve not been scared off yet… or eaten.",
          "Manor’s the heart of it, I think. Graveyard’s uglier. Well’s deadlier."
        ],
        "after_missing_alchemist": [
          "You brought her back. Folk needed this win."
        ],
        "after_restless_dead": [
          "East side can bury their dead again. That matters."
        ],
        "after_troll_trouble": [
          "Water’s ours again. Means no more pigs down a hole, and no more pretending tribute is strategy."
        ],
        "after_all_three": [
          "You’ve done more for Umberhold than any order I’ve given in months."
        ]
      }
    },
    {
      "id": "halvric",
      "name": "Warden Halvric",
      "role": "gate_warden",
      "summary": "An aging soldier with a rigid sense of duty.",
      "dialogue": {
        "default": [
          "Not safe beyond the walls. Not anymore.",
          "Road south looks open, if you don’t know better."
        ],
        "after_missing_alchemist": [
          "Orders changed. About time."
        ],
        "after_restless_dead": [
          "Heard the graveyard settled. Good."
        ],
        "after_troll_trouble": [
          "Water’s safe, they say. Good."
        ]
      }
    },
    {
      "id": "etheldreda",
      "name": "Etheldreda",
      "role": "alchemist",
      "summary": "Missing at game start; unlocked as a potion vendor after rescue.",
      "unlocks_after_flag": "etheldreda_rescued",
      "dialogue": {
        "default": [
          "You have my thanks… though I’d have preferred to meet you under less infernal circumstances."
        ],
        "after_restless_dead": [
          "I can smell grave-soil less strongly on the wind now."
        ],
        "after_troll_trouble": [
          "Clean water improves every brew I make."
        ],
        "after_all_three": [
          "Perhaps I shall hang a proper sign again. Open, maybe."
        ]
      }
    }
  ],
  "quests": [
    {
      "id": "the_missing_alchemist",
      "title": "The Missing Alchemist",
      "quest_type": "main",
      "difficulty_hint": "intended_first_path",
      "available_early": true,
      "ideal_after_manor": false,
      "source_npc_id": "wymarc",
      "source_summary": "Wymarc suspects Etheldreda was taken near Gravenhold Manor and did not leave willingly.",
      "journal_summary_incomplete": "Etheldreda, Umberhold’s alchemist, has vanished. The locked shop and Wymarc’s unease point toward Gravenhold Manor.",
      "journal_summary_complete": "Etheldreda was rescued from beneath Gravenhold Manor after being forced to brew for the Boggart Boss.",
      "objectives": [
        {
          "id": "investigate_manor",
          "text": "Investigate Gravenhold Manor."
        },
        {
          "id": "rescue_etheldreda",
          "text": "Rescue Etheldreda."
        },
        {
          "id": "defeat_boss",
          "text": "Defeat the Boggart Boss beneath the manor."
        }
      ],
      "reward": {
        "gp": 1000,
        "lesser_item_rolls": 3,
        "greater_item_rolls": 1
      },
      "village_consequences": [
        "etheldreda_returns",
        "alchemy_shop_reopens",
        "villagers_more_visible_outdoors",
        "hopeful_gossip_unlocked"
      ],
      "hidden_truth": "Etheldreda is held beneath the manor and forced to brew strengthening potions."
    },
    {
      "id": "the_restless_dead",
      "title": "The Restless Dead",
      "quest_type": "side",
      "difficulty_hint": "high",
      "available_early": true,
      "ideal_after_manor": true,
      "source_npc_id": "wymarc",
      "source_summary": "The graveyard east of the village no longer lets the dead rest.",
      "journal_summary_incomplete": "Something has disturbed the graveyard east of Umberhold. A dark stair in the rear mausoleum seems to lead below to the source.",
      "journal_summary_complete": "The corruption beneath Umberhold’s graveyard has been broken and the site can be mourned in peace again.",
      "objectives": [
        {
          "id": "investigate_graveyard",
          "text": "Investigate the graveyard."
        },
        {
          "id": "enter_mausoleum",
          "text": "Descend the dark stair in the rear mausoleum."
        },
        {
          "id": "destroy_undead_presence",
          "text": "Destroy the undead presence below."
        }
      ],
      "reward": {
        "gp": 500,
        "lesser_item_rolls": 2
      },
      "village_consequences": [
        "funeral_rites_resume",
        "flowers_and_candles_return_to_graves",
        "gidney_relief_dialogue"
      ]
    },
    {
      "id": "troll_trouble",
      "title": "Troll Trouble",
      "quest_type": "side",
      "difficulty_hint": "very_high",
      "available_early": true,
      "ideal_after_manor": true,
      "source_npc_id": "wymarc",
      "source_summary": "Trolls below the village well have seized the water source and forced tribute from the villagers.",
      "journal_summary_incomplete": "Trolls have taken the village well and the water below it. If the party descends with the rope and bucket rig, they will enter immediate combat.",
      "journal_summary_complete": "The trolls below the well are dead and the village water is safe again.",
      "objectives": [
        {
          "id": "inspect_well",
          "text": "Inspect the village well."
        },
        {
          "id": "descend_well",
          "text": "Descend into the well using the rope and bucket."
        },
        {
          "id": "kill_trolls",
          "text": "Kill the trolls below and climb back out."
        }
      ],
      "reward": {
        "gp": 500,
        "lesser_item_rolls": 2
      },
      "village_consequences": [
        "clean_water_returns",
        "villagers_gather_at_well",
        "optional_inn_discount",
        "trade_improves"
      ]
    }
  ],
  "progression": {
    "south_gate_locked_until_flag": "south_gate_unlocked",
    "recommended_order": [
      "the_missing_alchemist",
      "the_restless_dead",
      "troll_trouble"
    ],
    "village_flags": [
      "q_missing_alchemist_started",
      "q_missing_alchemist_complete",
      "q_restless_dead_started",
      "q_restless_dead_complete",
      "q_troll_trouble_started",
      "q_troll_trouble_complete",
      "etheldreda_rescued",
      "alchemist_shop_reopened",
      "graveyard_stabilized",
      "well_secured",
      "south_gate_unlocked"
    ]
  }
}
"}

